  1	import {
  2	  Button,
  3	  Flex,
  4	  FlexItem,
  5	  Menu,
  6	  MenuContent,
  7	  MenuItem,
  8	  MenuList,
  9	  Popper,
 10	  TextInput,
 11	  ValidatedOptions
 12	} from '@patternfly/react-core';
 13	import { CaretDownIcon } from '@patternfly/react-icons';
 14	import * as _ from 'lodash';
 15	import * as React from 'react';
 16	import { createFilterValue, FilterDefinition, FilterOption, FilterValue } from '../../../model/filters';
 17	import { getGenericHTTPError } from '../../../utils/errors';
 18	import { undefinedValue } from '../../../utils/filter-definitions';
 19	import { Indicator } from '../../../utils/filters-helper';
 20	import './autocomplete-filter.css';
 21	
 22	const optionsMenuID = 'options-menu-list';
 23	const isMenuOption = (elt?: Element) => {
 24	  return elt?.parentElement?.id === optionsMenuID || elt?.parentElement?.parentElement?.id === optionsMenuID;
 25	};
 26	
 27	export interface AutocompleteFilterProps {
 28	  filterDefinition: FilterDefinition;
 29	  addFilter: (filter: FilterValue) => boolean;
 30	  setMessage: (m: string | undefined) => void;
 31	  indicator: Indicator;
 32	  setIndicator: (ind: Indicator) => void;
 33	  currentValue: string;
 34	  setCurrentValue: (v: string) => void;
 35	}
 36	
 37	export const AutocompleteFilter: React.FC<AutocompleteFilterProps> = ({
 38	  filterDefinition,
 39	  addFilter: addFilterParent,
 40	  setMessage,
 41	  indicator,
 42	  setIndicator,
 43	  currentValue,
 44	  setCurrentValue
 45	}) => {
 46	  const autocompleteContainerRef = React.useRef<HTMLDivElement | null>(null);
 47	  const searchInputRef = React.useRef<HTMLInputElement | null>(null);
 48	  const optionsRef = React.useRef<HTMLDivElement | null>(null);
 49	  const [options, setOptions] = React.useState<FilterOption[]>([]);
 50	
 51	  React.useEffect(() => {
 52	    if (_.isEmpty(currentValue)) {
 53	      setIndicator(ValidatedOptions.default);
 54	    } else {
 55	      //update validation icon on field on value change
 56	      const validation = filterDefinition.validate(currentValue);
 57	      setIndicator(validation.err ? ValidatedOptions.warning : ValidatedOptions.success);
 58	    }
 59	    // eslint-disable-next-line react-hooks/exhaustive-deps
 60	  }, [currentValue, filterDefinition, setIndicator]);
 61	
 62	  const resetFilterValue = React.useCallback(() => {
 63	    setCurrentValue('');
 64	    setOptions([]);
 65	    setMessage(undefined);
 66	    setIndicator(ValidatedOptions.default);
 67	  }, [setCurrentValue, setMessage, setIndicator, setOptions]);
 68	
 69	  const addFilter = React.useCallback(
 70	    (option: FilterOption) => {
 71	      const filter: FilterValue = filterDefinition.autoCompleteAddsQuotes
 72	        ? { v: `"${option.value}"`, display: `"${option.name}"` }
 73	        : { v: option.value, display: option.name };
 74	      if (addFilterParent(filter)) {
 75	        resetFilterValue();
 76	      }
 77	    },
 78	    [filterDefinition, addFilterParent, resetFilterValue]
 79	  );
 80	
 81	  const onAutoCompleteChange = React.useCallback(
 82	    (newValue: string) => {
 83	      setCurrentValue(newValue);
 84	      filterDefinition
 85	        .autocomplete(newValue)
 86	        .then(setOptions)
 87	        .catch(err => {
 88	          const errorMessage = getGenericHTTPError(err);
 89	          setMessage(errorMessage);
 90	          setOptions([]);
 91	        });
 92	    },
 93	    [setOptions, setCurrentValue, filterDefinition, setMessage]
 94	  );
 95	
 96	  const onAutoCompleteOptionSelected = React.useCallback(
 97	    (option: FilterOption) => {
 98	      if (filterDefinition.checkCompletion) {
 99	        const completion = filterDefinition.checkCompletion(currentValue, option.name);
100	        if (completion.completed) {
101	          addFilter(completion.option);
102	        } else {
103	          onAutoCompleteChange(completion.option.value);
104	        }
105	      } else {
106	        addFilter(option);
107	        setOptions([]);
108	      }
109	    },
110	    [addFilter, onAutoCompleteChange, filterDefinition, currentValue, setOptions]
111	  );
112	
113	  const onAutoCompleteSelect = React.useCallback(
114	    (e: React.MouseEvent<Element, MouseEvent> | undefined, itemId: string) => {
115	      e?.stopPropagation();
116	      const option = options.find(opt => opt.value === itemId);
117	      if (!option) {
118	        return;
119	      }
120	      onAutoCompleteOptionSelected(option);
121	    },
122	    [options, onAutoCompleteOptionSelected]
123	  );
124	
125	  const onEnter = React.useCallback(() => {
126	    // override empty value by undefined value
127	    let v = currentValue;
128	    if (currentValue.length === 0) {
129	      v = undefinedValue;
130	    }
131	
132	    // Only one choice is present, consider this is what is desired
133	    if (options.length === 1) {
134	      onAutoCompleteOptionSelected(options[0]);
135	      return;
136	    }
137	
138	    const validation = filterDefinition.validate(v);
139	    //show tooltip and icon when user try to validate filter
140	    if (!_.isEmpty(validation.err)) {
141	      setMessage(validation.err);
142	      setIndicator(ValidatedOptions.error);
143	      return;
144	    }
145	
146	    const fv = createFilterValue(filterDefinition, validation.val!);
147	    if (addFilterParent(fv)) {
148	      resetFilterValue();
149	    }
150	  }, [
151	    options,
152	    filterDefinition,
153	    currentValue,
154	    onAutoCompleteOptionSelected,
155	    setMessage,
156	    setIndicator,
157	    addFilterParent,
158	    resetFilterValue
159	  ]);
160	
161	  const onBlur = React.useCallback(() => {
162	    // Timeout hack: we need to reset autocompletion / close popup
163	    // only if the focus isn't moved from the text input to the popup itself
164	    // We need to skip a couple of render frames to get the new focused element
165	    setTimeout(() => {
166	      if (!isMenuOption(document.activeElement || undefined)) {
167	        setOptions([]);
168	      }
169	    }, 50);
170	  }, []);
171	
172	  return (
173	    <Flex direction={{ default: 'row' }}>
174	      <div
175	        id="autocomplete-container"
176	        data-test="autocomplete-container"
177	        ref={autocompleteContainerRef}
178	        className="flex"
179	      >
180	        <Popper
181	          trigger={
182	            <TextInput
183	              type="search"
184	              aria-label="search"
185	              validated={indicator}
186	              placeholder={filterDefinition.placeholder}
187	              value={currentValue}
188	              onKeyDown={e => {
189	                if (e.key === 'Enter') {
190	                  onEnter();
191	                  e.preventDefault();
192	                }
193	              }}
194	              onChange={(event, value) => onAutoCompleteChange(value)}
195	              onBlur={onBlur}
196	              ref={searchInputRef}
197	              data-test="autocomplete-search"
198	              id="autocomplete-search"
199	            />
200	          }
201	          popper={
202	            <Menu ref={optionsRef} onSelect={onAutoCompleteSelect} isScrollable={options.length > 8}>
203	              <MenuContent>
204	                <MenuList id={optionsMenuID}>
205	                  {options.map(option => (
206	                    <MenuItem data-test={option.value} itemId={option.value} key={option.name} onBlur={onBlur}>
207	                      {option.name}
208	                    </MenuItem>
209	                  ))}
210	                </MenuList>
211	              </MenuContent>
212	            </Menu>
213	          }
214	          isVisible={!_.isEmpty(options)}
215	          enableFlip={false}
216	          appendTo={autocompleteContainerRef.current || undefined}
217	        />
218	      </div>
219	      <FlexItem>
220	        <Button
221	          icon={<CaretDownIcon />}
222	          data-test="autocomplete-menu-button"
223	          id="autocomplete-menu-button"
224	          variant="control"
225	          aria-label="show values"
226	          onClick={() =>
227	            setTimeout(() => {
228	              if (_.isEmpty(options)) {
229	                onAutoCompleteChange(currentValue);
230	              } else {
231	                setOptions([]);
232	              }
233	            }, 100)
234	          }
235	        ></Button>
236	      </FlexItem>
237	    </Flex>
238	  );
239	};
240	
241	export default AutocompleteFilter;

