 1	import { ValidatedOptions } from '@patternfly/react-core';
 2	import { act, fireEvent, render, waitFor } from '@testing-library/react';
 3	import * as React from 'react';
 4	
 5	import { FilterDefinitionSample } from '../../../../components/__tests-data__/filters';
 6	import { findFilter } from '../../../../utils/filter-definitions';
 7	import AutocompleteFilter, { AutocompleteFilterProps } from '../autocomplete-filter';
 8	
 9	describe('<AutocompleteFilter />', () => {
10	  const props: AutocompleteFilterProps = {
11	    filterDefinition: findFilter(FilterDefinitionSample, 'src_name')!,
12	    indicator: ValidatedOptions.default,
13	    currentValue: '',
14	    setCurrentValue: jest.fn(),
15	    addFilter: jest.fn(),
16	    setMessage: jest.fn(),
17	    setIndicator: jest.fn()
18	  };
19	  beforeEach(() => {
20	    props.setCurrentValue = jest.fn();
21	    props.addFilter = jest.fn();
22	    props.setIndicator = jest.fn();
23	  });
24	
25	  it('should filter valid port by name', async () => {
26	    const { container, rerender } = render(
27	      <AutocompleteFilter {...props} filterDefinition={findFilter(FilterDefinitionSample, 'src_port')!} />
28	    );
29	    const input = container.querySelector('#autocomplete-search') as HTMLInputElement;
30	    expect(input).toBeTruthy();
31	
32	    expect(props.addFilter).toHaveBeenCalledTimes(0);
33	    expect(props.setIndicator).toHaveBeenCalledTimes(1);
34	
35	    await act(async () => {
36	      fireEvent.change(input, { target: { value: 'ftp' } });
37	    });
38	    expect(props.setCurrentValue).toHaveBeenNthCalledWith(1, 'ftp');
39	
40	    rerender(
41	      <AutocompleteFilter
42	        {...props}
43	        filterDefinition={findFilter(FilterDefinitionSample, 'src_port')!}
44	        currentValue="ftp"
45	      />
46	    );
47	    await act(async () => {
48	      fireEvent.keyDown(input, { key: 'Enter' });
49	    });
50	
51	    await waitFor(() => {
52	      expect(props.addFilter).toHaveBeenNthCalledWith(1, { v: '21', display: 'ftp' });
53	    });
54	  });
55	
56	  it('should reject invalid port by name', async () => {
57	    const { container, rerender } = render(
58	      <AutocompleteFilter {...props} filterDefinition={findFilter(FilterDefinitionSample, 'dst_port')!} />
59	    );
60	    const input = container.querySelector('#autocomplete-search') as HTMLInputElement;
61	    expect(input).toBeTruthy();
62	
63	    expect(props.addFilter).toHaveBeenCalledTimes(0);
64	    expect(props.setIndicator).toHaveBeenCalledTimes(1);
65	
66	    await act(async () => {
67	      fireEvent.change(input, { target: { value: 'no match' } });
68	    });
69	    expect(props.setCurrentValue).toHaveBeenNthCalledWith(1, 'no match');
70	
71	    rerender(
72	      <AutocompleteFilter
73	        {...props}
74	        filterDefinition={findFilter(FilterDefinitionSample, 'dst_port')!}
75	        currentValue="no match"
76	      />
77	    );
78	    expect(props.setIndicator).toHaveBeenNthCalledWith(2, ValidatedOptions.warning);
79	
80	    await act(async () => {
81	      fireEvent.keyDown(input, { key: 'Enter' });
82	    });
83	
84	    await waitFor(() => {
85	      expect(props.setIndicator).toHaveBeenNthCalledWith(3, ValidatedOptions.error);
86	      expect(props.addFilter).toHaveBeenCalledTimes(0);
87	    });
88	  });
89	});

